def initialize(sandbox, project, platform, subgroup_name, group_name, app_target_label, add_main: true,
                         add_launchscreen_storyboard: platform == :ios, info_plist_entries: {}, product_basename: nil)
            @sandbox = sandbox
            @project = project
            @platform = platform
            @subgroup_name = subgroup_name
            @group_name = group_name
            @app_target_label = app_target_label
            @add_main = add_main
            @add_launchscreen_storyboard = add_launchscreen_storyboard
            @info_plist_entries = info_plist_entries
            @product_basename = product_basename || app_target_label
            target_group = project.pod_group(group_name)
            @group = target_group[subgroup_name] || target_group.new_group(subgroup_name)
          end

def initialize(sandbox, podfile, locked_dependencies, sources, specs_updated,
                   podfile_dependency_cache: Installer::Analyzer::PodfileDependencyCache.from_podfile(podfile),
                   sources_manager: Config.instance.sources_manager)
      @sandbox = sandbox
      @podfile = podfile
      @locked_dependencies = locked_dependencies
      @sources = Array(sources)
      @specs_updated = specs_updated
      @podfile_dependency_cache = podfile_dependency_cache
      @sources_manager = sources_manager
      @platforms_by_dependency = Hash.new { |h, k| h[k] = [] }

      @cached_sets = {}
      @podfile_requirements_by_root_name = @podfile_dependency_cache.podfile_dependencies.group_by(&:root_name).each_value { |a| a.map!(&:requirement).freeze }.freeze
      @search = {}
      @validated_platforms = Set.new
    end

def run_finalizers(result_path, finalizer_or_finalizers, result_data, result_key)
        if finalizer_or_finalizers.is_a?(Array)
          finalizer_or_finalizers.each { |f|
            f.path = result_path
            f.finalize_graphql_result(@query, result_data, result_key)
          }
          @finalizers_count -= finalizer_or_finalizers.size
        else
          f = finalizer_or_finalizers
          f.path = result_path
          f.finalize_graphql_result(@query, result_data, result_key)
          @finalizers_count -= 1
        end
      end

def initialize(object:, runner:, graphql_result:, key:, is_non_null:, field_resolve_step:, next_objects:, next_results:, is_from_array:)
        @object = object
        @runner = runner
        @field_resolve_step = field_resolve_step
        @is_non_null = is_non_null
        @next_objects = next_objects
        @next_results = next_results
        @graphql_result = graphql_result
        @resolved_type = nil
        @authorized_value = nil
        @authorization_error = nil
        @key = key
        @next_step = :resolve_type
        @is_from_array = is_from_array
      end

def on_fragment_definition(node, parent)
          object_type = if node.type
            @types.type(node.type.name)
          else
            @current_object_type
          end
          prev_parent_ot = @parent_object_type
          @parent_object_type = @current_object_type
          @current_object_type = object_type
          @path[@path_depth] = "fragment #{node.name}"
          @path_depth += 1
          super
          @current_object_type = @parent_object_type
          @parent_object_type = prev_parent_ot
          @path_depth -= 1
        end

def end_validate(query, validate, validation_errors)
        end_ts = ts
        @packets << trace_packet(
          timestamp: end_ts,
          type: TrackEvent::Type::TYPE_SLICE_END,
          track_uuid: fid,
          extra_counter_track_uuids: @counts_objects,
          extra_counter_values: [count_allocations],
        )

        if @create_debug_annotations
          new_bv_track_event = dup_with(
            @begin_validate.track_event, {
              debug_annotations: [
                @begin_validate.track_event.debug_annotations.first,
                payload_to_debug("valid?", validation_errors.empty?)
              ]
            }
          )
          @begin_validate.track_event = new_bv_track_event
        end
        super
      end
